# install_matam.ps1
# ----------------------------------------------------------------------
# Self-extracting installer for the MATAM Car Management System.
#
# HOW TO USE:
#   1. Copy this file to the SERVER PC (any Windows 10 / 11 machine).
#   2. Open PowerShell in the folder containing this file.
#   3. Run:
#        Set-ExecutionPolicy -Scope Process Bypass -Force
#        .\install_matam.ps1
#      (If saved as install_matam.txt, first rename it to .ps1)
#
# WHAT IT DOES:
#   * Creates an install folder (default: C:\matam_server\)
#   * Writes every project file (HTML, scripts, docs, schema, ...)
#     from embedded base64 payloads
#   * Downloads pocketbase.exe (~30 MB) directly from the official
#     public GitHub release: https://github.com/pocketbase/pocketbase
#   * Optionally runs install_server.cmd for one-click setup
#
# NO INTEL FILES ARE INCLUDED. pocketbase.exe is open-source software
# fetched from its public release page over HTTPS.
# ----------------------------------------------------------------------

[CmdletBinding()]
param(
    [string]$InstallDir  = 'C:\matam_server',
    [switch]$SkipDownload,
    [switch]$SkipInstall,
    [switch]$Force
)

$ErrorActionPreference = 'Stop'
$ProgressPreference    = 'SilentlyContinue'

$PbVersion = '0.39.7'
$PbZipName = 'pocketbase_0.39.7_windows_amd64.zip'
$PbUrl     = 'https://github.com/pocketbase/pocketbase/releases/download/v0.39.7/pocketbase_0.39.7_windows_amd64.zip'

Write-Host ''
Write-Host '=================================================================='
Write-Host '  MATAM Car System - text-based installer'
Write-Host '=================================================================='
Write-Host ''
Write-Host "Target folder : $InstallDir"
Write-Host "PocketBase    : v$PbVersion  ($PbUrl)"
Write-Host ''

if (Test-Path $InstallDir) {
    if (-not $Force) {
        $existing = Get-ChildItem $InstallDir -File -ErrorAction SilentlyContinue | Measure-Object
        if ($existing.Count -gt 0) {
            Write-Host "Folder already contains $($existing.Count) file(s)."
            $ans = Read-Host 'Overwrite existing files? [y/N]'
            if ($ans -notmatch '^(y|Y|yes)') {
                Write-Host 'Aborted.'
                exit 1
            }
        }
    }
} else {
    New-Item -ItemType Directory -Path $InstallDir -Force | Out-Null
}

Write-Host ''
Write-Host '[1/3] Writing embedded files...'
$files = New-Object System.Collections.Generic.List[object]
$files.Add([PSCustomObject]@{ Path = 'change_admin_password.cmd'; Content = @'

'@ })
$files.Add([PSCustomObject]@{ Path = 'collections_schema.json'; Content = @'

