$files.Add([PSCustomObject]@{ Path = 'initial_users.json'; Content = @'
H4sIAAAAAAAEAIvm5VJQqAYRCgpKqbmJmTlKVgpKiSm5mXkOuYklibl6OfnJiTlKOlAlBYnFxeX5RSkgVWB5IwMjM7hsUX5OKkQmLzE9tQgunpJZXJCTWOmXmAuWvj7v+oLrU67PUbi+4vqE6yuvz1QCqavl5Yrl5QIAGC7gZ5EAAAA=
