function Expand-Gz([byte[]]$Compressed) {
    if ($Compressed.Length -eq 0) { return ,([byte[]]@()) }
    $ms = New-Object System.IO.MemoryStream(,$Compressed)
    $gz = New-Object System.IO.Compression.GZipStream($ms, [System.IO.Compression.CompressionMode]::Decompress)
    $out = New-Object System.IO.MemoryStream
    $gz.CopyTo($out)
    $gz.Close()
    return $out.ToArray()
}

foreach ($f in $files) {
    $target = Join-Path $InstallDir ($f.Path -replace '/','\')
    $dir = Split-Path $target
    if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
    $gzBytes = [Convert]::FromBase64String($f.Content)
    $bytes = Expand-Gz -Compressed $gzBytes
    [System.IO.File]::WriteAllBytes($target, $bytes)
    Write-Host ("  {0,-45}  {1,7} bytes" -f $f.Path, $bytes.Length)
}

Write-Host ''
Write-Host '[2/3] Downloading pocketbase.exe from GitHub...'
$pbExe = Join-Path $InstallDir 'pocketbase.exe'
if ($SkipDownload) {
    Write-Host "  -SkipDownload specified, skipping download."
} elseif ((Test-Path $pbExe) -and (-not $Force)) {
    Write-Host "  pocketbase.exe already present, skipping download."
} else {
    $tmpZip = Join-Path $env:TEMP $PbZipName
    try {
        Write-Host "  GET $PbUrl"
        Invoke-WebRequest -Uri $PbUrl -OutFile $tmpZip -UseBasicParsing
        $sz = (Get-Item $tmpZip).Length
        Write-Host "  downloaded $([math]::Round($sz/1MB,2)) MB"
        Write-Host "  extracting..."
        Add-Type -AssemblyName System.IO.Compression.FileSystem
        $zip = [System.IO.Compression.ZipFile]::OpenRead($tmpZip)
        try {
            $entry = $zip.Entries | Where-Object { $_.Name -eq 'pocketbase.exe' } | Select-Object -First 1
            if ($null -eq $entry) { throw 'pocketbase.exe not found inside the release zip.' }
            [System.IO.Compression.ZipFileExtensions]::ExtractToFile($entry, $pbExe, $true)
        } finally {
            $zip.Dispose()
        }
        Remove-Item $tmpZip -Force
        Write-Host "  wrote pocketbase.exe ($([math]::Round((Get-Item $pbExe).Length/1MB,2)) MB)"
    } catch {
        Write-Warning "Failed to download pocketbase.exe: $_"
        Write-Host ''
        Write-Host 'MANUAL FALLBACK:'
        Write-Host "  1. On any PC with internet, download:"
        Write-Host "     $PbUrl"
        Write-Host "  2. Extract pocketbase.exe from that zip"
        Write-Host "  3. Copy pocketbase.exe into: $InstallDir"
        Write-Host "  4. Re-run this script with -SkipDownload, or run install_server.cmd directly"
        exit 1
    }
}

Write-Host ''
Write-Host '[3/3] Running install_server.cmd...'
if ($SkipInstall) {
    Write-Host '  -SkipInstall specified. All files are in place.'
    Write-Host "  When ready, run:  $InstallDir\install_server.cmd"
} else {
    Push-Location $InstallDir
    try {
        cmd /c install_server.cmd
    } finally {
        Pop-Location
    }
}

Write-Host ''
Write-Host '=================================================================='
Write-Host '  Done.'
Write-Host "  Install folder : $InstallDir"
Write-Host '  Next steps     : read INSTALLATION_GUIDE.md in that folder'
Write-Host '=================================================================='
